import com.zhihui.yanxue.data.model.Article
import com.zhihui.yanxue.data.model.Banner

/**
 * 文章Mock数据仓库
 * 基于天津红色文化真实素材，为首页5个Tab提供图文文章数据
 *
 * 数据来源：天津政务网、百度百科、天津文化和旅游局等公开资料
 *
 * Tab结构：
 * - 学习：2个专栏（红色地标、革命人物），共10篇
 * - 推荐：3篇置顶 + 2个专栏共7篇 = 10篇
 * - 探索：2个专栏（沉浸体验、互动学习），共10篇
 * - 观点：2个专栏（专家视角、青年之声），共10篇
 * - 专题：2个专栏（红色线路、主题教育），共10篇
 */
object MockArticleRepository {

    /** 获取指定Tab的所有文章 */
    fun getArticlesByTab(tab: String): List<Article> {
        return allArticles.filter { it.tab == tab }
    }

    /** 获取指定Tab的置顶文章 */
    fun getPinnedArticles(tab: String): List<Article> {
        return allArticles.filter { it.tab == tab && it.isPinned }
    }

    /** 获取指定Tab的非置顶文章 */
    fun getNormalArticles(tab: String): List<Article> {
        return allArticles.filter { it.tab == tab && !it.isPinned }
    }

    /** 获取指定Tab下某个专栏的文章 */
    fun getArticlesBySection(tab: String, section: String): List<Article> {
        return allArticles.filter { it.tab == tab && it.section == section }
    }

    /** 获取指定Tab的所有专栏名称（按出现顺序去重） */
    fun getSectionsByTab(tab: String): List<String> {
        return allArticles.filter { it.tab == tab }.map { it.section }.distinct()
    }

    /** 根据ID获取文章 */
    fun getArticleById(id: String): Article? {
        return allArticles.find { it.id == id }
    }

    /** 获取首页Banner轮播数据（5张） */
