            "学习", "革命人物", "article_interactive", "\u5929\u6d25\u515a\u53f2\u7814\u7a76\u5ba4", "2025-04-02", 1893, false,
            listOf("于方舟", "五四运动", "天津党组织")),

        Article("a008", "\u5409\u9e3f\u660c\uff1a\u6297\u65e5\u6c11\u65cf\u82f1\u96c4\u7684\u575a\u5b9a\u4fe1\u5ff5",
            "\u5409\u9e3f\u660c\u5c06\u519b\u7684\u82f1\u52c7\u4e8b\u8ff9\uff0c\u518d\u73b0\u5176\u575a\u5b9a\u4fe1\u5ff5\u548c\u7231\u56fd\u60c5\u6000",
            "\u5409\u9e3f\u660c\u662f\u6297\u65e5\u6c11\u65cf\u82f1\u96c4\uff0c\u4ed6\u7684\u4e8b\u8ff9\u611f\u52a8\u7740\u4e00\u4ee3\u53c8\u4e00\u4ee3\u4e2d\u56fd\u4eba\u3002\u4ed6\u5728\u6297\u65e5\u6218\u4e89\u4e2d\u5c65\u5efa\u5947\u529f\uff0c\u540e\u6765\u906d\u53cd\u52a8\u6d3e\u8feb\u5bb3\uff0c\u4f46\u59cb\u7ec8\u575a\u8d1e\u4e0d\u5c48\u3002\n\n1934\u5e7411\u670824\u65e5\uff0c\u5409\u9e3f\u660c\u5c06\u519b\u6177\u6167\u5c31\u4e49\u3002\u4ed6\u5728\u5211\u573a\u4e0a\u5199\u4e0b\u201c\u6068\u4e0d\u6297\u65e5\u6b7b\uff0c\u7559\u4f5c\u4eca\u65e5\u7f9e\u3002\u56fd\u7834\u5c1a\u5982\u6b64\uff0c\u6211\u4f55\u60dc\u6b64\u5934\u201d\u7684\u5c31\u4e49\u8bd7\uff0c\u8868\u73b0\u51fa\u9762\u5bf9\u6b7b\u4ea1\u7684\u5766\u7136\u548c\u5bf9\u7956\u56fd\u7684\u6df1\u6c89\u7231\u3002\u4eca\u5929\uff0c\u4ed6\u7684\u65e7\u5c45\u5df2\u4fee\u7f59\u4e00\u65b0\uff0c\u6210\u4e3a\u4f20\u627f\u7ea2\u8272\u57fa\u56e0\u7684\u91cd\u8981\u573a\u6240\u3002",
            "学习", "革命人物", "article_map", "\u5409\u9e3f\u660c\u751f\u5e73\u5c55\u7b79\u5907\u7ec4", "2025-04-08", 3421, false,
            listOf("吉鸿昌", "抗日英雄", "将军")),

        Article("a009", "\u9093\u9896\u8d85\uff1a\u5973\u6027\u9769\u547d\u5148\u9a71\u7684\u5149\u8f89\u4e00\u751f",
            "\u9093\u9896\u8d85\u662f\u4e2d\u56fd\u5987\u5973\u8fd0\u52a8\u7684\u5148\u9a71\uff0c\u5979\u4e0e\u5468\u6069\u6765\u540c\u751f\u5171\u6c7b\uff0c\u4e3a\u9769\u547d\u4e8b\u4e1a\u594b\u6597\u7ec8\u751f",
            "\u9093\u9896\u8d85\u662f\u4e2d\u56fd\u5987\u5973\u8fd0\u52a8\u7684\u5148\u9a71\uff0c\u4e5f\u662f\u5468\u6069\u6765\u7684\u9769\u547d\u4f34\u4fa3\u3002\u5979\u4e0e\u5468\u6069\u6765\u5728\u5929\u6d25\u76f8\u8bc6\uff0c\u5171\u540c\u6295\u8eab\u4e94\u56db\u8fd0\u52a8\uff0c\u7ec4\u7ec7\u89c9\u609f\u793e\u3002\n\n\u9093\u9896\u8d85\u4e00\u751f\u4e3a\u4e2d\u56fd\u5987\u5973\u89e3\u653e\u4e8b\u4e1a\u548c\u9769\u547d\u4e8b\u4e1a\u594b\u6597\uff0c\u5979\u7684\u5149\u8f89\u4e8b\u8ff9\u611f\u52a8\u7740\u65e0\u6570\u540e\u4eba\u3002\u5929\u6d25\u5468\u6069\u6765\u9093\u9896\u8d85\u7eaa\u5ff5\u9986\u5c31\u662f\u4e3a\u4e86\u7f05\u6000\u8fd9\u5bf9\u4f1f\u592b\u59bb\u800c\u5efa\u3002\u897f\u82b1\u5385\u5c55\u533a\u5b8c\u5168\u6309\u7167\u4e2d\u5357\u6d77\u897f\u82b1\u5385\u7684\u539f\u8c8c\u5e03\u5c40\u590d\u5236\uff0c\u8ba9\u4eba\u4eec\u80fd\u591f\u8fd1\u8ddd\u79bb\u611f\u53d7\u4f1f\u4eba\u7684\u751f\u6d3b\u3002",
            "学习", "革命人物", "banner_vr", "\u5468\u6069\u6765\u9093\u9896\u8d85\u7eaa\u5ff5\u9986", "2025-04-12", 2654, false,
            listOf("邓颖超", "妇女运动", "伟人")),

        Article("a010", "\u5b89\u5e78\u751f\uff1a\u5929\u6d25\u5de5\u4eba\u8fd0\u52a8\u7684\u9886\u519b\u4eba\u7269",
            "\u5b89\u5e78\u751f\u662f\u5929\u6d25\u5de5\u4eba\u8fd0\u52a8\u7684\u9886\u519b\u4eba\u7269\uff0c\u4e3a\u5929\u6d25\u7684\u9769\u547d\u4e8b\u4e1a\u732e\u51fa\u4e86\u5b9d\u8d35\u751f\u547d",
            "\u5b89\u5e78\u751f\u662f\u5929\u6d25\u5de5\u4eba\u8fd0\u52a8\u7684\u9886\u519b\u4eba\u7269\uff0c\u4ed6\u7684\u6545\u5c45\u73b0\u5df2\u4f5c\u4e3a\u7ea2\u8272\u6559\u80b2\u57fa\u5730\u5bf9\u5916\u5f00\u653e\u3002\u4ed6\u5728\u5929\u6d25\u7ec4\u7ec7\u5de5\u4eba\u8fd0\u52a8\uff0c\u4e3a\u4e2d\u56fd\u5171\u4ea7\u515a\u5728\u5929\u6d25\u7684\u5730\u4e0b\u7ec4\u7ec7\u5efa\u8bbe\u4f5c\u51fa\u4e86\u91cd\u8981\u8d21\u732e\u3002\n\n\u4ed6\u7684\u6545\u4e8b\u662f\u5929\u6d25\u7ea2\u8272\u5386\u53f2\u7684\u91cd\u8981\u7ec4\u6210\u90e8\u5206\uff0c\u4ed6\u7684\u7231\u56fd\u7cbe\u795e\u548c\u9769\u547d\u4fe1\u5ff5\u6c38\u8fdc\u503c\u5f97\u6211\u4eec\u5b66\u4e60\u548c\u4f20\u627f\u3002",
            "学习", "革命人物", "banner_creative", "\u5929\u6d25\u515a\u53f2\u7814\u7a76\u5ba4", "2025-04-15", 1234, false,
