        Article("a011", "\u3010\u7279\u522b\u63a8\u8350\u3011\u5929\u6d25\u53d1\u5e036\u6761\u7ea2\u8272\u8d44\u6e90\u4f53\u9a8c\u7ebf\u8def",
            "\u65f6\u4ee3\u8db3\u8ff9\u3001\u603b\u7406\u98ce\u8303\u3001\u5e73\u6d25\u6218\u5f79\u3001\u5c0f\u697c\u6625\u79cb\u3001\u84df\u5dde\u70fd\u706b\u3001\u661f\u706b\u71ce\u539f\u2014\u20146\u6761\u7ebf\u8def\u7ec7\u5c31\u6d25\u6cbd\u5927\u5730\u201c\u7ea2\u8272\u5730\u56fe\u201d",
            "2024\u5e7411\u670828\u65e5\uff0c\u201c\u4fe1\u4ef0\u4e4b\u5149\u2014\u2014\u5929\u6d25\u5e02\u7ea2\u8272\u8d44\u6e90\u4f53\u9a8c\u7ebf\u8def\u53d1\u5e03\u4eea\u5f0f\u201d\u5728\u5929\u6d25\u6d77\u6cb3\u4f20\u5a92\u4e2d\u5fc3\u5927\u5267\u9662\u4e3e\u884c\uff0c\u73b0\u573a\u53d1\u5e03\u65f6\u4ee3\u8db3\u8ff9\u3001\u603b\u7406\u98ce\u8303\u3001\u5e73\u6d25\u6218\u5f79\u3001\u5c0f\u697c\u6625\u79cb\u3001\u84df\u5dde\u70fd\u706b\u3001\u661f\u706b\u71ce\u539f\u7b496\u6761\u7ea2\u8272\u8d44\u6e90\u4f53\u9a8c\u7ebf\u8def\u3002\n\n\u9664\u4e86\u5b9e\u5730\u53c2\u89c2\uff0c\u5e7f\u5927\u5e02\u6c11\u8fd8\u53ef\u4ee5\u901a\u8fc7\u624b\u673a\u5fae\u4fe1\u5c0f\u7a0b\u5e8f\u201c\u6253\u5361\u5929\u6d25\u7ea2\u201d\uff0c\u5728\u7ebf\u4e0a\u4f53\u9a8c6\u6761\u7ea2\u8272\u8d44\u6e90\u7ebf\u8def\u3002\u4e00\u6761\u6761\u95ea\u8000\u7ea2\u8272\u5149\u8f89\u7684\u7ebf\u8def\uff0c\u7ec7\u5c31\u8d77\u6d25\u6cbd\u5927\u5730\u7684\u201c\u7ea2\u8272\u5730\u56fe\u201d\u3002",
            "推荐", "精选推荐", "article_exhibition", "\u5929\u6d25\u5e02\u6587\u5316\u548c\u65c5\u6e38\u5c40", "2025-04-20", 8765, true,
            listOf("红色线路", "天津", "体验路线")),

        Article("a012", "\u3010\u7f6e\u9876\u3011VR\u6c89\u6d78\u5f0f\u4f53\u9a8c\uff1a\u8db3\u4e0d\u51fa\u6237\u611f\u53d7\u5929\u6d25\u7ea2\u8272\u6587\u5316",
            "\u6253\u5f00\u624b\u673a\uff0c\u5c31\u80fd\u6e38\u89c8\u5468\u6069\u6765\u9093\u9896\u8d85\u7eaa\u5ff5\u9986\u3001\u5e73\u6d25\u6218\u5f79\u7eaa\u5ff5\u9986\u7b49\u7ea2\u8272\u5730\u6807",
            "\u7528VR\u6280\u672f\u6253\u9020\u6c89\u6d78\u5f0f\u7ea2\u8272\u6587\u5316\u4f53\u9a8c\uff0c\u8db3\u4e0d\u51fa\u6237\u5c31\u80fd\u611f\u53d7\u5929\u6d25\u7684\u7ea2\u8272\u5386\u53f2\u3002\u6253\u5f00\u624b\u673a\uff0c\u5c31\u80fd\u6e38\u89c8\u5468\u6069\u6765\u9093\u9896\u8d85\u7eaa\u5ff5\u9986\u3001\u5e73\u6d25\u6218\u5f79\u7eaa\u5ff5\u9986\u3001\u89c9\u609f\u793e\u7eaa\u5ff5\u9986\u7b49\u7ea2\u8272\u5730\u6807\u3002\n\nVR\u4f53\u9a8c\u8ba9\u5386\u53f2\u4ece\u4e66\u672c\u4e2d\u8d70\u51fa\u6765\uff0c\u8ba9\u5b66\u751f\u80fd\u591f\u201c\u8e0f\u5165\u201d\u5386\u53f2\u73b0\u573a\uff0c\u4e0e\u5386\u53f2\u4eba\u7269\u201c\u5bf9\u8bdd\u201d\uff0c\u8fd9\u662f\u4f20\u7edf\u6559\u80b2\u65b9\u5f0f\u65e0\u6cd5\u6bd4\u62df\u7684\u3002",
            "推荐", "精选推荐", "banner_vr", "\u667a\u7ed8\u7814\u5b66\u5f00\u53d1\u56e2\u961f", "2025-04-22", 6543, true,
            listOf("VR体验", "沉浸式", "红色文化")),

        Article("a013", "\u3010\u7f6e\u9876\u3011\u9752\u5c11\u5e74\u7684\u7ea2\u8272\u4fe1\u4ef0\uff1a\u5982\u4f55\u8ba9\u7ea2\u8272\u7cbe\u795e\u7167\u4eae\u6210\u957f\u4e4b\u8def",
            "\u7ea2\u8272\u7cbe\u795e\u662f\u57ce\u5e02\u7684\u6839\u4e0e\u9b42\uff0c\u521b\u65b0\u4f20\u627f\u65b9\u5f0f\u8ba9\u7ea2\u8272\u6587\u5316\u6d3b\u8d77\u6765",
            "\u7ea2\u8272\u7cbe\u795e\u5982\u4f55\u7167\u4eae\u9752\u5c11\u5e74\u6210\u957f\u4e4b\u8def\uff1f\u8fd9\u662f\u4e00\u4e2a\u503c\u5f97\u6df1\u601d\u7684\u8bdd\u9898\u3002\u7ea2\u8272\u6587\u5316\u4e0d\u4ec5\u4ec5\u662f\u5386\u53f2\u7684\u8bb0\u5fc6\uff0c\u66f4\u662f\u6d3b\u7684\u7cbe\u795e\u8d22\u5bcc\u3002\n\n\u521b\u65b0\u4f20\u627f\u65b9\u5f0f\uff0c\u8ba9\u7ea2\u8272\u6587\u5316\u6d3b\u8d77\u6765\u3002\u4ece\u77ed\u89c6\u9891\u5230VR\u4f53\u9a8c\uff0c\u4ece\u7814\u5b66\u5b66\u4e60\u5230\u5b9e\u5730\u53c2\u89c2\uff0c\u591a\u79cd\u65b9\u5f0f\u8ba9\u7ea2\u8272\u7cbe\u795e\u5728\u9752\u5c11\u5e74\u5fc3\u4e2d\u751f\u6839\u53d1\u82bd\u3002",
            "推荐", "精选推荐", "banner_memorial", "\u6d25\u95e8\u7ea2\u8272\u8bfe\u5802\u9879\u76ee\u7ec4", "2025-04-25", 5432, true,
            listOf("青少年", "红色信仰", "传承")),

        // 推荐-专栏1: 热门话题
        Article("a014", "\u6e05\u660e\u5047\u671f\u5929\u6d25\u7ea2\u8272\u666f\u70b9\u89c2\u4f17\u7eba\u7ec7\u4e0d\u7edd",
            "\u6e05\u660e\u5047\u671f\uff0c\u4e00\u5ea7\u5ea7\u535a\u7269\u9986\u5982\u540c\u6d25\u95e8\u82b1\u6d77\u95f4\u7684\u201c\u6587\u5316\u5ba2\u5385\u201d",
            "\u6e05\u660e\u5047\u671f\uff0c\u516b\u65b9\u6e38\u4eba\u6765\u6d25\u8d4f\u6625\u666f\u3001\u901b\u5c55\u9986\uff0c\u4e00\u5ea7\u5ea7\u535a\u7269\u9986\u5982\u540c\u6d25\u95e8\u82b1\u6d77\u95f4\u7684\u201c\u6587\u5316\u5ba2\u5385\u201d\uff0c\u4ee4\u4eba\u6c90\u6d74\u6587\u535a\u6625\u98ce\uff0c\u91cd\u6e29\u7ea2\u8272\u8bb0\u5fc6\uff0c\u611f\u53d7\u6587\u5316\u5e95\u8272\u3002\n\n\u5728\u5468\u6069\u6765\u9093\u9896\u8d85\u7eaa\u5ff5\u9986\u897f\u82b1\u5385\u7684\u82b1\u5f71\u95f4\u611f\u609f\u5d07\u9ad8\u7cbe\u795e\uff1b\u4e8e\u5e73\u6d25\u6218\u5f79\u7eaa\u5ff5\u9986\u5e7f\u573a\u7684\u82cd\u7fe0\u4e2d\u7f05\u6000\u9769\u547d\u5148\u70c8\u3002",
            "推荐", "热门话题", "banner_military", "\u5929\u6d25\u6587\u5316\u4f20\u5a92", "2025-04-07", 4321, false,
            listOf("清明", "红色旅游", "博物馆")),

        Article("a015", "\u201c\u6253\u5361\u5929\u6d25\u7ea2\u201d\u5c0f\u7a0b\u5e8f\u4e0a\u7ebf\uff0c\u7ebf\u4e0a\u4f53\u9a8c\u7ea2\u8272\u8def\u7ebf",
            "\u901a\u8fc7\u624b\u673a\u5fae\u4fe1\u5c0f\u7a0b\u5e8f\uff0c\u5728\u7ebf\u4e0a\u4f53\u9a8c6\u6761\u7ea2\u8272\u8d44\u6e90\u7ebf\u8def",
            "\u9664\u4e86\u5b9e\u5730\u53c2\u89c2\uff0c\u5e7f\u5927\u5e02\u6c11\u8fd8\u53ef\u4ee5\u901a\u8fc7\u624b\u673a\u5fae\u4fe1\u5c0f\u7a0b\u5e8f\u201c\u6253\u5361\u5929\u6d25\u7ea2\u201d\uff0c\u5728\u7ebf\u4e0a\u4f53\u9a8c6\u6761\u7ea2\u8272\u8d44\u6e90\u7ebf\u8def\u3002\n\n\u8fd9\u662f\u5929\u6d25\u5e02\u521b\u65b0\u7ea2\u8272\u8d44\u6e90\u4f20\u627f\u65b9\u5f0f\u7684\u91cd\u8981\u4e3e\u63aa\uff0c\u8ba9\u66f4\u591a\u4eba\u80fd\u591f\u65b9\u4fbf\u5730\u4e86\u89e3\u548c\u4f53\u9a8c\u5929\u6d25\u7684\u7ea2\u8272\u6587\u5316\u3002",
            "推荐", "热门话题", "article_interactive", "\u5929\u6d25\u5e02\u6587\u5316\u548c\u65c5\u6e38\u5c40", "2025-04-18", 3210, false,
            listOf("小程序", "线上体验", "红色线路")),

        Article("a016", "\u201c\u6d77\u6dc0\u7ebf\u4e0a\u201d\u5929\u6d25\u7ea2\u8272\u6587\u5316\u77ed\u89c6\u9891\u7cfb\u5217",
