        // 推荐-专栏2: 特色活动
        Article("a017", "\u7ea2\u8272\u6587\u5316\u521b\u610f\u5e02\u96c6\uff1a\u6587\u521b\u4ea7\u54c1\u5c55\u793a\u7ea2\u8272\u9b45\u529b",
            "\u5e06\u5e03\u888b\u3001\u62fc\u56fe\u3001\u51b0\u7bb1\u8d34\u3001\u80f6\u5e26\u30013D\u79ef\u6728\u2014\u2014\u7ea2\u8272\u6587\u521b\u8ba9\u5386\u53f2\u53ef\u89e6\u6478",
            "\u7ea2\u8272\u6587\u5316\u521b\u610f\u5e02\u96c6\u5c55\u793a\u4e86\u4e30\u5bcc\u591a\u5f69\u7684\u6587\u521b\u4ea7\u54c1\uff0c\u5e06\u5e03\u888b\u3001\u62fc\u56fe\u3001\u51b0\u7bb1\u8d34\u3001\u80f6\u5e26\u30013D\u79ef\u6728\u7b49\u7ea2\u8272\u6587\u521b\u8ba9\u5386\u53f2\u53ef\u89e6\u6478\u3001\u53ef\u611f\u53d7\u3002\n\n\u8fd9\u4e9b\u4ea7\u54c1\u5c06\u7ea2\u8272\u5143\u7d20\u4e0e\u73b0\u4ee3\u8bbe\u8ba1\u7ed3\u5408\uff0c\u8ba9\u5e74\u8f7b\u4eba\u5728\u65e5\u5e38\u751f\u6d3b\u4e2d\u611f\u53d7\u7ea2\u8272\u6587\u5316\u7684\u9b45\u529b\u3002",
            "推荐", "特色活动", "article_students", "\u667a\u7ed8\u7814\u5b66\u5f00\u53d1\u56e2\u961f", "2025-05-01", 2345, false,
            listOf("文创", "创意市集", "红色文化")),

        Article("a018", "\u7ea2\u8272\u77e5\u8bc6\u7ade\u8d5b\uff1a\u4ee5\u8d5b\u4fc3\u5b66\uff0c\u70b9\u71ce\u9752\u5e74\u4fe1\u4ef0",
